head.script:
scwin.cntrLineErrorMessage = "Off Hire Line 코드[@]와 컨테이너 [@]의 Line코드[@]가 일치하지 않습니다.";
scwin.cntrCurrPosErrorMessage = "작업장 코드[@]와 컨테이너 [@]의 현위치코드[@]가 일치하지 않습니다.";
scwin.cntrEmptyErrorMessage = "해당 컨테이너 [@]는 EMPTY 컨테이너가 아닙니다.";

scwin.oldCntrNo = "";
scwin.oldCntrRow = -1;

scwin.hid_odrKndCd = "";
scwin.hid_odrJobType = "";
scwin.hid_offhire_shpCoClntNo = "";
scwin.hid_onhire_shpCoClntNo = "";

scwin.cntrNoInfo = "";

scwin.ODR_KND_CD_ON_HIRE_ODR = "C5";
scwin.ODR_KND_CD_OFF_HIRE_ODR = "C6";
scwin.YN_NO = "0";
scwin.YN_YES = "1";
scwin.SELF_CLS_CD_MCOM_TRANS = "LS";
scwin.TB_JOB_INSERT = "1";
scwin.TB_JOB_UPDATE = "2";

scwin.onpageload = function() {
    scwin.cntrNoInfo = $c.data.getParameter() != null ? ($c.data.getParameter()["cntrNo"] || "") : "";
    scwin.lobranCd = $c.ses.getLobranCd();
    scwin.hid_odrKndCd = scwin.ODR_KND_CD_ON_HIRE_ODR;
    scwin.f_defaultValue();
    if (!$c.gus.cfIsNull(scwin.cntrNoInfo)) {
        scwin.f_Create();
        scwin.f_addRow();
        ds_cntrBasisInfo.setCellData(ds_cntrBasisInfo.getRowPosition(), "cntrNo", scwin.cntrNoInfo);
        if (scwin.f_checkCntrNo(scwin.cntrNoInfo)) {
            scwin.f_retrieveCntrBasisInfo(scwin.cntrNoInfo);
        }
    }
};

scwin.onUdcCompleted = function() {
};

scwin.f_defaultValue = function() {
    scwin.f_clearDataSetAll();
    $c.gus.cfDisableKeyData();
    $c.gus.cfDisableAllBtn();
    $c.gus.cfEnableBtnOnly([btnCreate]);
    scwin.f_DisablePopUpObj();
    $c.gus.cfEnableObjects([udc_wrkPl]);
    gr_commInfo.setReadOnly("grid", true);
    gr_cntrInfo.setReadOnly("grid", true);
    ed_cntrNo.setFocus();
};

scwin.f_clearDataSetAll = function() {
    ds_offhireOrder.removeAll();
    ds_offhireOrder.insertRow();

    ds_onhireOrder.removeAll();
    ds_onhireOrder.insertRow();

    ds_offhireOrderCommodity.removeAll();
    ds_onhireOrderCommodity.removeAll();

    ds_offhireOrderContainer.removeAll();
    ds_onhireOrderContainer.removeAll();

    ds_offhireOrderContainerInformation.removeAll();
    ds_onhireOrderContainerInformation.removeAll();
    ds_cntrBasisInfo.removeAll();

    scwin.f_clearData();
};

scwin.f_clearData = function() {
    let offRow = ds_offhireOrder.getRowPosition();
    ds_offhireOrder.setCellData(offRow, "odrKndCd", scwin.ODR_KND_CD_OFF_HIRE_ODR);
    ds_offhireOrder.setCellData(offRow, "selfClsCd", scwin.SELF_CLS_CD_MCOM_TRANS);
    ds_offhireOrder.setCellData(offRow, "smsSndYn", scwin.YN_NO);
    ds_offhireOrder.setCellData(offRow, "coshippingYn", scwin.YN_NO);
    ds_offhireOrder.setCellData(offRow, "odrDcsnYn", scwin.YN_YES);
    ds_offhireOrder.setCellData(offRow, "odrCompleteYn", scwin.YN_NO);
    ds_offhireOrder.setCellData(offRow, "odrCnclYn", scwin.YN_NO);
    ds_offhireOrder.setCellData(offRow, "odrDelYn", scwin.YN_NO);
    ds_offhireOrder.setCellData(offRow, "wrkPatternCd", "00");
    ds_offhireOrder.setCellData(offRow, "chClsCd", "0");
    ds_offhireOrder.setCellData(offRow, "regBranCd", scwin.lobranCd);
    ds_offhireOrder.setCellData(offRow, "autoOdrYn", scwin.YN_YES);

    let onRow = ds_onhireOrder.getRowPosition();
    ds_onhireOrder.setCellData(onRow, "odrKndCd", scwin.ODR_KND_CD_ON_HIRE_ODR);
    ds_onhireOrder.setCellData(onRow, "selfClsCd", scwin.SELF_CLS_CD_MCOM_TRANS);
    ds_onhireOrder.setCellData(onRow, "smsSndYn", scwin.YN_NO);
    ds_onhireOrder.setCellData(onRow, "coshippingYn", scwin.YN_NO);
    ds_onhireOrder.setCellData(onRow, "odrDcsnYn", scwin.YN_YES);
    ds_onhireOrder.setCellData(onRow, "odrCompleteYn", scwin.YN_NO);
    ds_onhireOrder.setCellData(onRow, "odrCnclYn", scwin.YN_NO);
    ds_onhireOrder.setCellData(onRow, "odrDelYn", scwin.YN_NO);
    ds_onhireOrder.setCellData(onRow, "wrkPatternCd", "00");
    ds_onhireOrder.setCellData(onRow, "chClsCd", "0");
    ds_onhireOrder.setCellData(onRow, "regBranCd", scwin.lobranCd);
    ds_onhireOrder.setCellData(onRow, "autoOdrYn", scwin.YN_YES);

    rd_offhire_sellYn.setValue(scwin.YN_NO);
    rd_onhire_sellYn.setValue(scwin.YN_NO);
};

scwin.f_EnablePopUpObj = function() {
    $c.gus.cfEnableObjects([udc_wrkPl, udc_offhire_line, udc_onhire_line]);
};

scwin.f_DisablePopUpObj = function() {
    $c.gus.cfDisableObjects([udc_wrkPl, udc_offhire_line, udc_onhire_line]);
};

scwin.f_Retrieve = async function() {
    if (await $c.gus.cfValidate([ed_cntrNo])) {
        scwin.f_clearDataSetAll();
        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableAllBtn();
        $c.gus.cfEnableBtnOnly([btnCreate]);
        scwin.f_DisablePopUpObj();
        scwin.hid_odrJobType = "";
        await $c.sbm.execute(sbm_retrieve);
    }
};

scwin.f_Create = function() {
    $c.gus.cfTurnCreateFlag(true);
    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();
    scwin.hid_odrJobType = scwin.TB_JOB_INSERT;
    $c.gus.cfDisableAllBtn();
    $c.gus.cfEnableBtnOnly([btnSave, btnAddRow, btnDeleteRow, btnUndoRow]);
    scwin.f_EnablePopUpObj();
    scwin.f_clearDataSetAll();
    ds_orderQueryCondition.removeAll();
    ds_orderQueryCondition.insertRow();
    gr_cntrInfo.setReadOnly("grid", false);

    let currDate = new Date();
    ed_wrkDt.setValue(WebSquare.date.getCurrentServerDate("yyyyMMdd"));
    ed_wrkHh.setValue(scwin.leadingZeros(currDate.getHours(), 2) + scwin.leadingZeros(currDate.getMinutes(), 2));

    ed_wrkPlCd.setFocus();
};

scwin.f_update = function() {
    $c.gus.cfEnableKeyData();
    $c.gus.cfDisableKey();
    scwin.hid_odrJobType = scwin.TB_JOB_UPDATE;
    $c.gus.cfDisableAllBtn();
    $c.gus.cfEnableBtnOnly([btnCreate, btnSave, btnDelete, btnAddRow, btnDeleteRow, btnUndoRow]);
    scwin.f_EnablePopUpObj();
    gr_cntrInfo.setReadOnly("grid", false);
    ed_wrkPlCd.setFocus();
};

scwin.f_save = async function() {
    if (scwin.hid_odrJobType == scwin.TB_JOB_UPDATE) {
        if (ds_offhireOrder.getUpdatedIndex().length == 0
            && ds_offhireOrderContainer.getUpdatedIndex().length == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["오더정보"]);
            return false;
        }
    }
    if (!(ed_offhire_lineCd.getValue() == "MOL" && ed_onhire_lineCd.getValue() == "ONE")) {
        if (txt_offhire_shpCoClntNm.getValue() != txt_onhire_shpCoClntNm.getValue()) {
            await $c.win.alert("Off Hire 선사와 On Hire 선사가 다릅니다.");
            return false;
        }
    }
    if (await scwin.f_validChk()) {
        let chk = await $c.gus.cfConfirmMsg(MSG_CM_CRM_001, ["Direct On/Off Hire 오더"]);
        if (chk) {
            $c.gus.cfShowDSWaitMsg(gr_cntrInfo);
            await $c.sbm.execute(sbm_save);
        }
    }
};

scwin.f_delete = async function() {
    let chk = await $c.gus.cfConfirmMsg("오더번호 : " + MSG_CM_CRM_008, [ed_onhire_odrNo.getValue() + " / " + ed_offhire_odrNo.getValue()]);
    if (chk) {
        ds_offhireOrder.removeRow(ds_offhireOrder.getRowPosition());
        for (let i = ds_offhireOrderContainerInformation.getRowCount() - 1; i >= 0; i--) {
            ds_offhireOrderContainerInformation.removeRow(i);
        }
        ds_onhireOrder.removeRow(ds_onhireOrder.getRowPosition());
        for (let i = ds_onhireOrderContainerInformation.getRowCount() - 1; i >= 0; i--) {
            ds_onhireOrderContainerInformation.removeRow(i);
        }
        await $c.sbm.execute(sbm_delete);
    }
};

scwin.f_validChk = async function() {
    let chk1 = await $c.gus.cfValidate([gr_cntrInfo]);
    if (chk1) {
        for (let i = 0; i < ds_onhireOrderContainerInformation.getRowCount(); i++) {
            ds_onhireOrderContainerInformation.setCellData(i, "arrvlportDtm", ed_wrkDt.getValue() + ed_wrkHh.getValue());
            ds_onhireOrderContainerInformation.setCellData(i, "lineCd", ed_onhire_lineCd.getValue());
        }
        for (let i = 0; i < ds_onhireOrderContainer.getRowCount(); i++) {
            ds_onhireOrderContainer.setCellData(i, "arrvlportDtm", ed_wrkDt.getValue() + ed_wrkHh.getValue());
        }
        return true;
    } else {
        return false;
    }
};

scwin.f_openPopUpOdrNo = async function() {
    let args = {
        paramTitle: "오더검색팝업",
        cntrNo: ed_cntrNo.getValue().trim(),
        odrKndCd: scwin.hid_odrKndCd
    };
    let rtnList = await $c.win.openPopup("/ui/ds/sd/odrmgnt/odrreg/sd_402_01_31p.xml", {
        width: 820,
        height: 400,
        modal: true,
        data: args
    });
    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            ed_onhire_odrNo.setValue(rtnList[0]);
            ed_cntrNo.setValue(rtnList[1]);
        }
    }
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    } else {
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
    }
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList = [];
    switch (disGubun) {
        case 1:
            rtnList = $c.gus.cfCommonPopUp("retrieveWrkPlInfo2", pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "작업장,작업장코드,작업장명");
            $c.gus.cfSetReturnValue(rtnList, ed_wrkPlCd, txt_wrkPlNm);
            break;
        case 2:
            rtnList = $c.gus.cfCommonPopUp("retrieveLineInfoList", pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "Off Hire LINE,LINE코드,LINE명");
            $c.gus.cfSetReturnValue(rtnList, ed_offhire_lineCd, txt_offhire_lineNm, [, , scwin.hid_offhire_shpCoClntNo, txt_offhire_shpCoClntNm]);
            break;
        case 3:
            rtnList = $c.gus.cfCommonPopUp("retrieveLineInfoList", pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, "On Hire LINE,LINE코드,LINE명");
            $c.gus.cfSetReturnValue(rtnList, ed_onhire_lineCd, txt_onhire_lineNm, [, , scwin.hid_onhire_shpCoClntNo, txt_onhire_shpCoClntNm]);
            break;
    }
};

scwin.f_addRow = function() {
    ds_cntrBasisInfo.insertRow();
};

scwin.f_deleteRow = function() {
    if (ds_cntrBasisInfo.getRowPosition() >= 0) {
        scwin.f_deleteCntrBasisInfo(ds_cntrBasisInfo.getRowPosition(), ds_cntrBasisInfo.getCellData(ds_cntrBasisInfo.getRowPosition(), "cntrNo"));
        ds_cntrBasisInfo.removeRow(ds_cntrBasisInfo.getRowPosition());
    }
};

scwin.f_undoRow = function() {
    if (ds_cntrBasisInfo.getRowPosition() >= 0) {
        scwin.f_undoCntrBasisInfo();
        ds_cntrBasisInfo.undoAll();
    }
};

scwin.f_checkCntrNo = async function(parCntrNo) {
    let cntrNo = parCntrNo.trim();
    if (cntrNo != "") {
        if (!$c.gus.cf_CheckCntrNo(cntrNo)) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_038, ["컨테이너"]);
        }
    }
    return true;
};

scwin.f_retrieveCntrBasisInfo = async function(cntrNo) {
    if (!$c.gus.cfIsNull(cntrNo)) {
        dma_condCntrBasisInfo.set("cntrNo", cntrNo);
        await $c.sbm.execute(sbm_retrieveCntrBasisInfo);
    }
};

scwin.f_addCntrBasisInfo = async function(row) {
    if (ed_wrkPlCd.getValue() != ds_cntrBasisInfoResult.getCellData(row, "currPosCd")) {
        await $c.gus.cfAlertMsg(scwin.cntrCurrPosErrorMessage, [ed_wrkPlCd.getValue(), ds_cntrBasisInfoResult.getCellData(row, "cntrNo"), ds_cntrBasisInfoResult.getCellData(row, "currPosCd")]);
        ds_cntrBasisInfo.setCellData(ds_cntrBasisInfo.getRowPosition(), "cntrNo", scwin.oldCntrNo);
        return false;
    }

    if (ed_offhire_lineCd.getValue() != ds_cntrBasisInfoResult.getCellData(row, "lineCd")) {
        await $c.gus.cfAlertMsg(scwin.cntrLineErrorMessage, [ed_offhire_lineCd.getValue(), ds_cntrBasisInfoResult.getCellData(row, "cntrNo"), ds_cntrBasisInfoResult.getCellData(row, "lineCd")]);
        ds_cntrBasisInfo.setCellData(ds_cntrBasisInfo.getRowPosition(), "cntrNo", scwin.oldCntrNo);
        return false;
    }

    let inputTime = ed_wrkDt.getValue() + ed_wrkHh.getValue();
    if (inputTime < ds_cntrBasisInfoResult.getCellData(row, "maxArrvlPortDtm")) {
        await $c.win.alert("이미 만들어진 컨테이너 마스터의 값보다 작은 값이 입력 되었습니다. \n\n작업일시를 "
            + ds_cntrBasisInfoResult.getCellData(row, "maxArrvlPortDtm")
            + "보다 큰 값으로 입력해 주십시오.");
        ed_wrkDt.setFocus();
        return false;
    }

    if (ds_offhireOrderCommodity.getRowCount() > 0) {
        let chkOffhireOrderCommodity = false;
        let matchIdx = -1;
        for (let i = 0; i < ds_offhireOrderCommodity.getRowCount(); i++) {
            if (ds_offhireOrderCommodity.getCellData(i, "cntrSizCd") == ds_cntrBasisInfoResult.getCellData(row, "cntrSizCd")
                && ds_offhireOrderCommodity.getCellData(i, "cntrTypCd") == ds_cntrBasisInfoResult.getCellData(row, "cntrTypCd")
                && ds_offhireOrderCommodity.getCellData(i, "fullEmptyClsCd") == ds_cntrBasisInfoResult.getCellData(row, "fullEmptyClsCd")) {
                chkOffhireOrderCommodity = true;
                matchIdx = i;
                break;
            }
        }
        if (chkOffhireOrderCommodity) {
            ds_offhireOrderCommodity.setCellData(matchIdx, "odrNo", ds_offhireOrder.getCellData(ds_offhireOrder.getRowPosition(), "odrNo"));
            ds_offhireOrderCommodity.setCellData(matchIdx, "commSeq", ds_offhireOrderCommodity.getRowPosition() + 1);
            ds_offhireOrderCommodity.setCellData(matchIdx, "qtyUnitCd", "VAN");
            ds_offhireOrderCommodity.setCellData(matchIdx, "qty", Number(ds_offhireOrderCommodity.getCellData(ds_offhireOrderCommodity.getRowPosition(), "qty")) + 1);
            ds_offhireOrderCommodity.setCellData(matchIdx, "wrkStDt", ed_wrkDt.getValue());
            ds_offhireOrderCommodity.setCellData(matchIdx, "wrkStHh", ed_wrkHh.getValue());
            ds_offhireOrderCommodity.setCellData(matchIdx, "wrkEndDt", ed_wrkDt.getValue());
            ds_offhireOrderCommodity.setCellData(matchIdx, "wrkEndHh", ed_wrkHh.getValue());
        } else {
            ds_offhireOrderCommodity.insertRow();
            let pos = ds_offhireOrderCommodity.getRowPosition();
            ds_offhireOrderCommodity.setCellData(pos, "odrNo", ds_offhireOrder.getCellData(ds_offhireOrder.getRowPosition(), "odrNo"));
            ds_offhireOrderCommodity.setCellData(pos, "commSeq", pos + 1);
            ds_offhireOrderCommodity.setCellData(pos, "cntrSizCd", ds_cntrBasisInfoResult.getCellData(row, "cntrSizCd"));
            ds_offhireOrderCommodity.setCellData(pos, "cntrTypCd", ds_cntrBasisInfoResult.getCellData(row, "cntrTypCd"));
            ds_offhireOrderCommodity.setCellData(pos, "fullEmptyClsCd", ds_cntrBasisInfoResult.getCellData(row, "fullEmptyClsCd"));
            ds_offhireOrderCommodity.setCellData(pos, "qtyUnitCd", "VAN");
            ds_offhireOrderCommodity.setCellData(pos, "qty", 1);
            ds_offhireOrderCommodity.setCellData(pos, "wrkStDt", ed_wrkDt.getValue());
            ds_offhireOrderCommodity.setCellData(pos, "wrkStHh", ed_wrkHh.getValue());
            ds_offhireOrderCommodity.setCellData(pos, "wrkEndDt", ed_wrkDt.getValue());
            ds_offhireOrderCommodity.setCellData(pos, "wrkEndHh", ed_wrkHh.getValue());
        }
    } else {
        ds_offhireOrderCommodity.insertRow();
        let pos = ds_offhireOrderCommodity.getRowPosition();
        ds_offhireOrderCommodity.setCellData(pos, "odrNo", ds_offhireOrder.getCellData(ds_offhireOrder.getRowPosition(), "odrNo"));
        ds_offhireOrderCommodity.setCellData(pos, "commSeq", pos + 1);
        ds_offhireOrderCommodity.setCellData(pos, "cntrSizCd", ds_cntrBasisInfoResult.getCellData(row, "cntrSizCd"));
        ds_offhireOrderCommodity.setCellData(pos, "cntrTypCd", ds_cntrBasisInfoResult.getCellData(row, "cntrTypCd"));
        ds_offhireOrderCommodity.setCellData(pos, "fullEmptyClsCd", ds_cntrBasisInfoResult.getCellData(row, "fullEmptyClsCd"));
        ds_offhireOrderCommodity.setCellData(pos, "qtyUnitCd", "VAN");
        ds_offhireOrderCommodity.setCellData(pos, "qty", 1);
        ds_offhireOrderCommodity.setCellData(pos, "wrkStDt", ed_wrkDt.getValue());
        ds_offhireOrderCommodity.setCellData(pos, "wrkStHh", ed_wrkHh.getValue());
        ds_offhireOrderCommodity.setCellData(pos, "wrkEndDt", ed_wrkDt.getValue());
        ds_offhireOrderCommodity.setCellData(pos, "wrkEndHh", ed_wrkHh.getValue());
    }

    ds_offhireOrderContainer.insertRow();
    let offCntrPos = ds_offhireOrderContainer.getRowPosition();
    ds_offhireOrderContainer.setCellData(offCntrPos, "odrNo", ds_offhireOrder.getCellData(ds_offhireOrder.getRowPosition(), "odrNo"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "cntrSeq", offCntrPos + 1);
    ds_offhireOrderContainer.setCellData(offCntrPos, "arrvlportDtm", ds_cntrBasisInfoResult.getCellData(row, "arrvlportDtm"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "cntrNo", ds_cntrBasisInfoResult.getCellData(row, "cntrNo"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "cntrSizCd", ds_cntrBasisInfoResult.getCellData(row, "cntrSizCd"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "cntrTypCd", ds_cntrBasisInfoResult.getCellData(row, "cntrTypCd"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "fullEmptyClsCd", ds_cntrBasisInfoResult.getCellData(row, "fullEmptyClsCd"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "dptWrkPlCd", ed_wrkPlCd.getValue());
    ds_offhireOrderContainer.setCellData(offCntrPos, "arvWrkPlCd", ed_wrkPlCd.getValue());
    ds_offhireOrderContainer.setCellData(offCntrPos, "wrkStDt", ed_wrkDt.getValue());
    ds_offhireOrderContainer.setCellData(offCntrPos, "wrkStHh", ed_wrkHh.getValue());
    ds_offhireOrderContainer.setCellData(offCntrPos, "wrkEndDt", ed_wrkDt.getValue());
    ds_offhireOrderContainer.setCellData(offCntrPos, "wrkEndHh", ed_wrkHh.getValue());
    ds_offhireOrderContainer.setCellData(offCntrPos, "sellLodeptCd", ds_cntrBasisInfoResult.getCellData(row, "sellLodeptCd"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "sellYn", ds_cntrBasisInfoResult.getCellData(row, "sellYn"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "wt", ds_cntrBasisInfoResult.getCellData(row, "wt"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "temper", ds_cntrBasisInfoResult.getCellData(row, "temper"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "dryYn", ds_cntrBasisInfoResult.getCellData(row, "dryYn"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "cntrWtCondCd", ds_cntrBasisInfoResult.getCellData(row, "cntrWtCondCd"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "dcsnYn", ds_cntrBasisInfoResult.getCellData(row, "dcsnYn"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "dcsnDt", ds_cntrBasisInfoResult.getCellData(row, "dcsnDt"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "dcsnHh", ds_cntrBasisInfoResult.getCellData(row, "dcsnHh"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "completeYn", ds_cntrBasisInfoResult.getCellData(row, "completeYn"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "completeDt", ds_cntrBasisInfoResult.getCellData(row, "completeDt"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "completeHh", ds_cntrBasisInfoResult.getCellData(row, "completeHh"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "cfsInMthdCd", ds_cntrBasisInfoResult.getCellData(row, "cfsInMthdCd"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "cfsCmpndCgshfYn", ds_cntrBasisInfoResult.getCellData(row, "cfsCmpndCgshfYn"));
    ds_offhireOrderContainer.setCellData(offCntrPos, "cntrInsYn", ds_cntrBasisInfoResult.getCellData(row, "cntrInsYn"));
