        ds_onhireOrderCommodity.setCellData(pos2, "fullEmptyClsCd", ds_cntrBasisInfoResult.getCellData(row, "fullEmptyClsCd"));
        ds_onhireOrderCommodity.setCellData(pos2, "qtyUnitCd", "VAN");
        ds_onhireOrderCommodity.setCellData(pos2, "qty", 1);
        ds_onhireOrderCommodity.setCellData(pos2, "wrkStDt", ed_wrkDt.getValue());
        ds_onhireOrderCommodity.setCellData(pos2, "wrkStHh", ed_wrkHh.getValue());
        ds_onhireOrderCommodity.setCellData(pos2, "wrkEndDt", ed_wrkDt.getValue());
