scwin.f_deleteCntrBasisInfo = function(row, cntrNo) {
    let chkOffhireOrderCommodity = false;
    let matchIdx = -1;
    for (let i = 0; i < ds_offhireOrderCommodity.getRowCount(); i++) {
        if (ds_offhireOrderCommodity.getCellData(i, "cntrSizCd") == ds_cntrBasisInfo.getCellData(row, "cntrSizCd")
            && ds_offhireOrderCommodity.getCellData(i, "cntrTypCd") == ds_cntrBasisInfo.getCellData(row, "cntrTypCd")
            && ds_offhireOrderCommodity.getCellData(i, "fullEmptyClsCd") == ds_cntrBasisInfo.getCellData(row, "fullEmptyClsCd")) {
            chkOffhireOrderCommodity = true;
            matchIdx = i;
            break;
        }
    }
    if (chkOffhireOrderCommodity) {
        if (Number(ds_offhireOrderCommodity.getCellData(matchIdx, "qty")) > 1) {
            ds_offhireOrderCommodity.setCellData(matchIdx, "qty", Number(ds_offhireOrderCommodity.getCellData(matchIdx, "qty")) - 1);
        } else {
            ds_offhireOrderCommodity.removeRow(matchIdx);
        }
    }
    for (let i = 0; i < ds_offhireOrderContainer.getRowCount(); i++) {
        if (ds_offhireOrderContainer.getCellData(i, "cntrNo") == cntrNo) {
            ds_offhireOrderContainer.removeRow(i);
            break;
        }
    }
    for (let i = 0; i < ds_offhireOrderContainerInformation.getRowCount(); i++) {
        if (ds_offhireOrderContainerInformation.getCellData(i, "cntrNo") == cntrNo) {
            ds_offhireOrderContainerInformation.removeRow(i);
            break;
        }
    }

    let chkOnhireOrderCommodity = false;
    let matchIdx2 = -1;
    for (let i = 0; i < ds_onhireOrderCommodity.getRowCount(); i++) {
        if (ds_onhireOrderCommodity.getCellData(i, "cntrSizCd") == ds_cntrBasisInfo.getCellData(row, "cntrSizCd")
            && ds_onhireOrderCommodity.getCellData(i, "cntrTypCd") == ds_cntrBasisInfo.getCellData(row, "cntrTypCd")
            && ds_onhireOrderCommodity.getCellData(i, "fullEmptyClsCd") == ds_cntrBasisInfo.getCellData(row, "fullEmptyClsCd")) {
            chkOnhireOrderCommodity = true;
            matchIdx2 = i;
            break;
        }
    }
    if (chkOnhireOrderCommodity) {
        if (Number(ds_onhireOrderCommodity.getCellData(matchIdx2, "qty")) > 1) {
            ds_onhireOrderCommodity.setCellData(matchIdx2, "qty", Number(ds_onhireOrderCommodity.getCellData(matchIdx2, "qty")) - 1);
        } else {
            ds_onhireOrderCommodity.removeRow(matchIdx2);
        }
    }
    for (let i = 0; i < ds_onhireOrderContainer.getRowCount(); i++) {
        if (ds_onhireOrderContainer.getCellData(i, "cntrNo") == cntrNo) {
            ds_onhireOrderContainer.removeRow(i);
            break;
        }
    }
    for (let i = 0; i < ds_onhireOrderContainerInformation.getRowCount(); i++) {
        if (ds_onhireOrderContainerInformation.getCellData(i, "cntrNo") == cntrNo) {
            ds_onhireOrderContainerInformation.removeRow(i);
            break;
        }
    }
};

scwin.f_undoCntrBasisInfo = function() {
    ds_offhireOrderCommodity.undoAll();
    ds_offhireOrderContainer.undoAll();
    ds_offhireOrderContainerInformation.undoAll();
    ds_onhireOrderCommodity.undoAll();
    ds_onhireOrderContainer.undoAll();
    ds_onhireOrderContainerInformation.undoAll();
};

scwin.f_CopyDataSetCntrBasisInfo = function() {
    let srcRow = ds_cntrBasisInfoResult.getRowPosition();
    let tgtRow = ds_cntrBasisInfo.getRowPosition();
    let colIds = ds_cntrBasisInfoResult.getColumnIds();
    if (colIds && colIds.length) {
        for (let j = 0; j < colIds.length; j++) {
            let colId = colIds[j];
            ds_cntrBasisInfo.setCellData(tgtRow, colId, ds_cntrBasisInfoResult.getCellData(srcRow, colId));
        }
    }
};

scwin.f_clearCntrIndormation = function(objVal, gubun) {
    if (gubun == "line") {
        if ($c.gus.cfIsNull(objVal)) {
            ds_offhireOrderCommodity.removeAll();
            ds_offhireOrderContainer.removeAll();
            ds_offhireOrderContainerInformation.removeAll();
            ds_onhireOrderCommodity.removeAll();
            ds_onhireOrderContainer.removeAll();
            ds_onhireOrderContainerInformation.removeAll();
            ds_cntrBasisInfo.removeAll();
        }
    } else if (gubun == "wrkPlCd") {
        if ($c.gus.cfIsNull(objVal)) {
            ds_offhireOrderCommodity.removeAll();
            ds_offhireOrderContainer.removeAll();
            ds_offhireOrderContainerInformation.removeAll();
            ds_onhireOrderCommodity.removeAll();
            ds_onhireOrderContainer.removeAll();
            ds_onhireOrderContainerInformation.removeAll();
            ds_cntrBasisInfo.removeAll();
        }
    }
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([ed_cntrNo, ed_offhire_odrNo, ed_onhire_odrNo]);
};

scwin.leadingZeros = function(n, digits) {
    let zero = "";
    n = n.toString();
    if (n.length < digits) {
        for (let i = 0; i < digits - n.length; i++) {
            zero += "0";
        }
    }
    return zero + n;
};

