        ed_offhire_lineCd.setValue(ds_cntrBasisInfoResult.getCellData(0, "lineCd"));
        scwin.f_openCommonPopUp(2, ed_offhire_lineCd.getValue(), txt_offhire_lineNm.getValue(), "T", "F");

        await scwin.f_addCntrBasisInfo(ds_cntrBasisInfoResult.getRowPosition());
    }
};

