scwin.gr_cntrInfo_oneditend = async function(rowIndex, columnId, oldValue, newValue) {
    if (columnId == "cntrNo") {
        if (newValue != oldValue) {
            if (await scwin.f_checkCntrNo(newValue)) {
                for (let i = 0; i < ds_cntrBasisInfo.getRowCount(); i++) {
                    if (ds_cntrBasisInfo.getCellData(i, "cntrNo") == newValue) {
                        if (rowIndex != i && ds_cntrBasisInfo.getRowStatus(i) != "D") {
                            await $c.gus.cfAlertMsg(MSG_CM_ERR_031 + MSG_CM_ERR_032, ["컨테이너목록", (i + 1), "컨테이너번호"]);
                            ds_cntrBasisInfo.setCellData(rowIndex, "cntrNo", oldValue);
                            return;
                        }
                    }
                }
                scwin.oldCntrNo = oldValue;
                scwin.oldCntrRow = rowIndex;
                let cntrNo = ds_cntrBasisInfo.getCellData(rowIndex, "cntrNo");
                scwin.f_retrieveCntrBasisInfo(cntrNo);
            }
        }
    }
};
